const data = {
  name: "Alex",
  age: 25,
  score: null,
  active: true,
  address: { city: "London" },
  tags: ["js", "python"],
  secret: undefined,    // omitted!
  fn: () => {},         // omitted!
  created: new Date("2024-01-15"),  // becomes string
};

console.log(JSON.stringify(data));

const user = {
  name: "Alex",
  age: 25,
  address: { city: "London", country: "UK" },
  skills: ["JavaScript", "Python"],
};

// Compact (default):
console.log(JSON.stringify(user));
console.log("---");
// Pretty-printed:
console.log(JSON.stringify(user, null, 2));

function safeJsonParse(str) {
  try {
    return { data: JSON.parse(str), error: null };
  } catch (e) {
    return { data: null, error: e.message };
  }
}

const valid   = '{"name":"Alex","score":95}';
const invalid = '{name: "Alex"}';  // keys must have quotes in JSON

const r1 = safeJsonParse(valid);
const r2 = safeJsonParse(invalid);

console.log(r1.data.name, r1.data.score);
console.log(r2.error.includes("JSON") ? "Invalid JSON" : r2.error);

const user = {
  id: 1,
  name: "Alex",
  password: "secret123",    // should be excluded!
  email: "alex@example.com",
  createdAt: "2024-01-15",
};

// Array replacer — whitelist only these keys:
console.log(JSON.stringify(user, ["id", "name", "email"]));

// Function replacer — exclude password:
const sanitized = JSON.stringify(user, (key, value) => {
  if (key === "password") return undefined;  // omit
  return value;  // keep everything else
});
console.log(sanitized);

const json = '{"name":"Alex","createdAt":"2024-01-15T00:00:00.000Z","updatedAt":"2024-03-10T12:00:00.000Z"}';

// Without reviver — dates are strings:
const withoutReviver = JSON.parse(json);
console.log(typeof withoutReviver.createdAt);  // string

// With reviver — convert date strings to Date objects:
const withReviver = JSON.parse(json, (key, value) => {
  if (typeof value === 'string' && /^\d{4}-\d{2}-\d{2}T/.test(value)) {
    return new Date(value);
  }
  return value;
});
console.log(withReviver.createdAt instanceof Date); // true
console.log(withReviver.createdAt.getFullYear());   // 2024

class User {
  #password;  // private — should NOT be in JSON

  constructor(name, email, password) {
    this.name = name;
    this.email = email;
    this.#password = password;
    this.createdAt = new Date();
  }

  toJSON() {
    return {
      name: this.name,
      email: this.email,
      createdAt: this.createdAt.toISOString(),
      // password is never included
    };
  }
}

const user = new User("Alex", "alex@example.com", "secret!");
console.log(JSON.stringify(user));
console.log(JSON.stringify({ users: [user] }, null, 2).includes("password")); // false

// Normal stringify crashes on circular refs:
const obj = { name: "node" };
obj.self = obj; // circular!

try {
  JSON.stringify(obj);
} catch (e) {
  console.log("Error:", e.message.includes("circular") ? "Circular structure detected" : e.message);
}

// Safe stringify with circular detection:
function safeStringify(obj) {
  const seen = new Set();
  return JSON.stringify(obj, (key, value) => {
    if (typeof value === 'object' && value !== null) {
      if (seen.has(value)) return '[Circular]';
      seen.add(value);
    }
    return value;
  });
}

console.log(safeStringify(obj));
